import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PlayTime {
  totalHours: number;
  lastSession: number;
}

interface Achievement {
  name: string;
  date: string;
}

interface LevelProgress {
  level: number;
  experience: number;
}

interface GamingStats {
  gameTitle: string;
  playTime: PlayTime;
  achievements: {
    totalUnlocked: number;
    recent: Achievement[];
  };
  levelProgress: LevelProgress[];
}

interface MetaData {
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const gamingStats = response.data as GamingStats;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2E2E2E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF' }} fontWeight={600}>
              {gamingStats.gameTitle}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Total Play Time: {gamingStats.playTime.totalHours} hrs
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 1 }}>
              Last Session: {gamingStats.playTime.lastSession} hrs
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 0.5 }}>
              Recent Achievements
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {gamingStats.achievements.recent.slice(0, 3).map((achievement, index) => (
                <Chip
                  key={index}
                  label={achievement.name}
                  sx={{ fontSize: '11px', px: 1, color: '#FFFFFF', bgcolor: metaData.primaryColor }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ mt: 2 }}>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 0.5 }}>
              Level Progress
            </Typography>
            <BarChart
              height={140}
              series={[
                {
                  data: gamingStats.levelProgress.map(lp => lp.experience),
                  color: metaData.accentColor,
                },
              ]}
              xAxis={[
                {
                  data: gamingStats.levelProgress.map(lp => `L${lp.level}`),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#CFD8DC',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
